function App() {
  return (
    <div style={{ 
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      height: "100vh",
      backgroundColor: "#f3f6f9",
      fontFamily: "Arial"
    }}>

      {/* Avatar Placeholder */}
      <div style={{
        width: "150px",
        height: "150px",
        borderRadius: "50%",
        backgroundColor: "#cfd9e6",
        marginBottom: "20px"
      }}>
      </div>

      <h1>Welcome to Mental Health Chatbot</h1>
      <p>Your safe space to talk and heal</p>

      <div style={{ marginTop: "20px" }}>
        <button style={{ marginRight: "10px", padding: "10px 20px" }}>
          Login
        </button>
        <button style={{ padding: "10px 20px" }}>
          Sign Up
        </button>
      </div>

    </div>
  );
}

export default App;
